    text = p.get('text', '')
    title = p.get('filename', '').replace('.txt', '')

    # Year logic
    year = None
    m = re.search(r'Copyright.*?(\d{4})', text, re.IGNORECASE)
    if not m: m = re.search(r'©.*?(\d{4})', text)
    if not m: m = re.search(r'(\d{4})\s*ACM', text)
    if m:
        year = m.group(1)
    else:
        header = text[:1000]
        m2 = re.search(r"'\d{2}", header)
        if m2: year = "20" + m2.group(0)[1:]
        else:
            m3 = re.search(r'20\d{2}', header)
            if m3: year = m3.group(0)

