        debug_2016.append({"title": title, "has_pa": has_pa})

    if has_pa:
        debug_pa.append({"title": title, "year": year})

print("__RESULT__:")
print(json.dumps({"papers_2016": debug_2016, "papers_pa": debug_pa}))

